class Solution {
    public int countKDifference(int[] nums, int k) {
        Map<Integer, Integer> countMap = new HashMap<>();
        int count = 0;
        for (int num : nums) {
            count += countMap.getOrDefault(num - k, 0) + countMap.getOrDefault(num + k, 0);
            countMap.put(num, countMap.getOrDefault(num, 0) + 1);
        }
        return count;
    }
}
```

